export default function HVLInteraktivApp() {
  const [view, setView] = useState('dashboard');
  const [activities, setActivities] = useState([]);
  const [currentActivity, setCurrentActivity] = useState(null);

  useEffect(() => {
    const saved = localStorage.getItem('hvl_activities');
    if (saved) setActivities(JSON.parse(saved));
  }, []);

  useEffect(() => {
    try {
        localStorage.setItem('hvl_activities', JSON.stringify(activities));
    } catch (e) {
        if (e.name === 'QuotaExceededError') console.error("Storage full");
    }
  }, [activities]);

  const handleDownloadHTML = (activity) => {
    const htmlContent = `
