    <script src="https://unpkg.com/lucide@latest"></script>
    <script src="https://unpkg.com/babel-standalone@6/babel.min.js"></script>
    <style>
       @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;600;700&display=swap');
       body { font-family: 'Inter', sans-serif; background-color: #f8fafc; }
    </style>
</head>
<body>
    <div id="root"></div>

    <script type="text/babel">
        // --- INJECTED DATA ---
        const activity = ${JSON.stringify(activity)};
        const windowData = activity; // Alias for compatibility

        // --- ICONS ---
        const { 
          Hexagon, CheckCircle2, HelpCircle, Play, Plus, Save, Type, X, Trash2, Edit3, 
          Layout, Eye, RotateCw, FileJson, Upload, MapPin, ChevronRight, ChevronDown, 
          ChevronUp, ChevronLeft, Trophy, Layers, ArrowUp, ArrowDown, Video, MonitorPlay, 
          MousePointer2, Grid, FileVideo, Clock, Move, GripVertical, Lock, AlertCircle, 
          CalendarClock, Loader2, ArrowRight, RotateCcw, Target
        } = lucide;
        const { useState, useEffect, useRef, useMemo } = React;

        // Use lucide icons directly in the components below by referencing the variables above
        // We don't need the extra destructuring from 'lucideReact' in the template since we have them here.
        // But to make the copy-pasted template work without changes, we can shim it:
        const lucideReact = lucide; 

        // --- PLAYER COMPONENTS ---
        ${PLAYER_SCRIPT_TEMPLATE}

        const StandalonePlayer = () => {
            // Determine which player to render based on activity type
            const renderPlayer = () => {
                switch(activity.type) {
                    case 'Flervalg': return <MCPlayer data={activity.data} />;
                    case 'Sant/Usant': return <TFPlayer data={activity.data} />;
                    case 'Fyll inn': return <ClozePlayer data={activity.data} />;
                    case 'Bilde Hotspot': return <HotspotPlayer data={activity.data} />;
                    case 'Interaktiv Video': return <VideoPlayer data={activity.data} />;
                    case 'Tidslinje': return <TimelinePlayer data={activity.data} />;
                    case 'Dra og Slipp': return <DragDropPlayer data={activity.data} />;
                    case 'Minnespel': return <MemoryPlayer data={activity.data} />;
                    case 'Flere saman': return <MixedPlayer data={activity.data} />;
                    default: return <div>Ukjent aktivitet: {activity.type}</div>;
                }
            };

           return (
             <div className="min-h-screen bg-slate-50 p-4 md:p-8 font-sans text-slate-900">
                <div className="max-w-4xl mx-auto bg-white rounded-3xl shadow-xl overflow-hidden border border-slate-200">
                   <div className="bg-slate-800 text-white p-6">
                      <h1 className="text-2xl font-bold">{activity.title}</h1>
                      {activity.description && <p className="text-slate-400 text-sm mt-1">{activity.description}</p>}
                   </div>
                   <div className="p-6 md:p-12">
                       {renderPlayer()}
                   </div>
                </div>
             </div>
           );
        };

        const root = ReactDOM.createRoot(document.getElementById('root'));
        root.render(<StandalonePlayer />);
    </script>
</body>
</html>
    `;

    const blob = new Blob([htmlContent], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${activity.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleCreate = (type) => {
    const newActivity = {
      id: Date.now().toString(),
      type,
      title: `Utkast ${type}`,
      description: '',
      data: getDefaultData(type),
      createdAt: new Date().toISOString()
    };
    setCurrentActivity(newActivity);
    setView('editor');
  };

  const handleSave = (updatedActivity) => {
    setActivities(prev => {
      const exists = prev.find(a => a.id === updatedActivity.id);
      if (exists) return prev.map(a => a.id === updatedActivity.id ? updatedActivity : a);
      return [...prev, updatedActivity];
    });
    setCurrentActivity(updatedActivity);
  };

  const handleDelete = (id) => {
    setActivities(prev => prev.filter(a => a.id !== id));
  };

  const handleDuplicate = (activity) => {
    const newActivity = {
      ...activity,
      id: Date.now().toString(),
      title: `${activity.title} (Kopi)`,
      createdAt: new Date().toISOString()
    };
    setActivities(prev => [...prev, newActivity]);
  };

  const handleExport = () => {
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(activities));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href",     dataStr);
    downloadAnchorNode.setAttribute("download", "hvl_aktiviteter_backup.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const handleImport = (event) => {
    const file = event.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const imported = JSON.parse(e.target.result);
        if (Array.isArray(imported)) {
          setActivities(prev => {
            const combined = [...prev];
            imported.forEach(newItem => {
              const idx = combined.findIndex(existing => existing.id === newItem.id);
              if (idx >= 0) combined[idx] = newItem;
              else combined.push(newItem);
            });
            return combined;
          });
          alert(`Importerte ${imported.length} aktiviteter.`);
        } else {
          alert("Ugyldig filformat.");
        }
      } catch (error) {
        console.error(error);
        alert("Kunne ikke lese filen.");
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="min-h-screen bg-slate-100 text-slate-900 font-sans selection:bg-cyan-100">
      <nav className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between sticky top-0 z-50 shadow-sm">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => setView('dashboard')}>
          <div className="w-10 h-10 bg-cyan-700 rounded-lg flex items-center justify-center shadow-cyan-200 shadow-lg transform hover:scale-105 transition-transform">
            <Hexagon className="text-white w-6 h-6" strokeWidth={2.5} />
          </div>
          <div>
            <h1 className="font-bold text-xl tracking-tight text-slate-800 leading-none">HVL Interaktiv</h1>
            <p className="text-[10px] text-cyan-700 font-bold uppercase tracking-widest mt-1">Høgskulen på Vestlandet</p>
          </div>
        </div>
        <div className="flex gap-2">
           {view !== 'dashboard' && (
             <button onClick={() => setView('dashboard')} className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg text-sm font-bold transition-colors flex items-center gap-2">
               <Layout size={16}/> Hovedmeny
             </button>
           )}
           <button onClick={() => setView(view === 'help' ? 'dashboard' : 'help')} className={`px-4 py-2 rounded-lg text-sm font-bold transition-colors flex items-center gap-2 ${view === 'help' ? 'bg-cyan-50 text-cyan-700 border border-cyan-200' : 'bg-white text-slate-600 border border-slate-200 hover:bg-slate-50'}`}>
               <BookOpen size={16}/> Hvordan bruke HVL Interaktiv
           </button>
        </div>
      </nav>

      <main className="max-w-6xl mx-auto p-6">
        {view === 'dashboard' && (
          <Dashboard 
            activities={activities} 
            onCreate={handleCreate} 
            onEdit={(a) => { setCurrentActivity(a); setView('editor'); }} 
            onPlay={(a) => { setCurrentActivity(a); setView('player'); }} 
            onDelete={handleDelete}
            onDuplicate={handleDuplicate}
            onExport={handleExport}
            onImport={handleImport}
            onDownloadHTML={handleDownloadHTML}
          />
        )}
        {view === 'help' && <HelpPage />}
        {view === 'editor' && currentActivity && <Editor activity={currentActivity} onSave={handleSave} onPreview={() => setView('player')} />}
        {view === 'player' && currentActivity && <Player activity={currentActivity} onEdit={() => setView('editor')} />}
      </main>
    </div>
  );
}

