function Editor({ activity, onSave, onPreview }) {
  const [title, setTitle] = useState(activity.title);
  const [description, setDescription] = useState(activity.description || '');
  const [data, setData] = useState(activity.data);
  const [saved, setSaved] = useState(false);
  const [videoDuration, setVideoDuration] = useState(null);
  const [placingId, setPlacingId] = useState(null);
  const { upload, loading } = useMediaUpload();

  const handleSave = () => {
    onSave({ ...activity, title, description, data });
    setSaved(true);
    setTimeout(() => setSaved(false), 2000);
  };

  const handleVideoClick = (e) => {
      if (!placingId) return;
      const rect = e.currentTarget.getBoundingClientRect();
      const x = ((e.clientX - rect.left) / rect.width) * 100;
      const y = ((e.clientY - rect.top) / rect.height) * 100;

      // Update interaction with this placingId
      if (activity.type === 'Interaktiv Video') {
          if (data.scenes) {
              const newScenes = data.scenes.map(scene => ({
                  ...scene,
                  interactions: scene.interactions.map(i => i.id === placingId ? { ...i, x, y } : i)
              }));
              setData({ ...data, scenes: newScenes });
          } else {
              // Legacy flat structure
              const nInt = data.interactions.map(i => i.id === placingId ? { ...i, x, y } : i);
              setData({ ...data, interactions: nInt });
          }
      }
      setPlacingId(null);
  };

  // Auto-save on unmount logic could go here, but keeping manual for clarity

  const inputClass = "w-full p-2.5 border border-slate-300 rounded-lg text-sm bg-slate-50 focus:bg-white focus:border-cyan-500 focus:ring-2 focus:ring-cyan-100 transition-all outline-none";
  const labelClass = "block text-xs font-bold text-slate-500 uppercase tracking-wide mb-1.5 ml-1";

  const renderFlervalg = (d, update) => (
    <div className="space-y-6">
