                                          <input 
                                            type="number" 
                                            min="0" 
                                            max={videoDuration ? Math.floor(videoDuration) : undefined}
                                            value={intr.time} 
                                            onChange={e => {
                                              const n = [...scenes]; 
                                              let val = parseFloat(e.target.value);
                                              if (isNaN(val)) val = 0;
                                              if (val < 0) val = 0;
                                              if (videoDuration && val > videoDuration) val = Math.floor(videoDuration);
                                              n[idx].interactions[intIdx].time = val; 
