                            className={inputClass} 
                            placeholder="Alternativ tekst..." 
                          />
                      </div>

                      <div className="space-y-2">
                          <div className="flex justify-between items-center">
                               <label className={labelClass}>Definer Soner (Klikk på bildet)</label>
                               <span className="text-xs text-slate-400">Soner er der elementene skal slippes.</span>
                          </div>
                          <div className="relative border-2 border-slate-200 rounded-xl overflow-hidden bg-slate-100 min-h-[300px] cursor-crosshair shadow-inner" onClick={e => {
                               if(e.target === e.currentTarget) {
                                   const rect = e.currentTarget.getBoundingClientRect();
                                   const newZone = { id: Date.now(), label: 'Ny Sone', top: ((e.clientY - rect.top)/rect.height)*100, left: ((e.clientX - rect.left)/rect.width)*100, width: 15, height: 10 };
                                   const n = [...tasks];
                                   n[idx].zones = [...(n[idx].zones||[]), newZone];
                                   update({...d, tasks: n, backgroundUrl: undefined, altText: undefined, items: undefined, zones: undefined});
                               }
                          }}>
                              <img src={task.backgroundUrl} alt={task.altText} className="w-full h-auto pointer-events-none opacity-60" />
                              {(task.zones||[]).map(z => (
                                  <div key={z.id} style={{top: `${z.top}%`, left: `${z.left}%`, width: `${z.width}%`, height: `${z.height}%`}} className="absolute border-2 border-cyan-500 bg-white/80 flex items-center justify-center shadow-sm"><span className="text-xs font-bold px-1 truncate">{z.label}</span></div>
                              ))}
                          </div>
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                          <div className="border border-slate-200 p-4 rounded-xl bg-white">
                              <h5 className="text-sm font-bold text-cyan-700 mb-3 border-b border-cyan-100 pb-2">Soner</h5>
                              <SortableList items={task.zones||[]} listKey={`dnd-zones-${task.id}`} onUpdate={nZones => {
                                  const n = [...tasks];
                                  n[idx].zones = nZones;
                                  update({...d, tasks: n, backgroundUrl: undefined, altText: undefined, items: undefined, zones: undefined});
                              }} onRemove={zId => {
                                  const n = [...tasks];
                                  n[idx].zones = n[idx].zones.filter(z => z.id !== zId);
                                  update({...d, tasks: n, backgroundUrl: undefined, altText: undefined, items: undefined, zones: undefined});
                              }} labelFn={z => z.label} renderContent={(z, zIdx) => (
                                  <div>
                                      <label className={labelClass}>Navn på sone</label>
                                      <input value={z.label} onChange={e => {
                                          const n = [...tasks];
                                          n[idx].zones[zIdx].label = e.target.value;
                                          update({...d, tasks: n, backgroundUrl: undefined, altText: undefined, items: undefined, zones: undefined});
                                      }} className={inputClass} />
                                      <p className="text-xs text-slate-400 mt-2">Tips: Du kan endre størrelse i spilleren, men foreløpig er det fast størrelse her.</p>
                                  </div>
                              )} />
                          </div>
                          <div className="border border-slate-200 p-4 rounded-xl bg-white">
                              <h5 className="text-sm font-bold text-cyan-700 mb-3 border-b border-cyan-100 pb-2">Elementer</h5>
                              <SortableList items={task.items||[]} listKey={`dnd-items-${task.id}`} onUpdate={nItems => {
                                  const n = [...tasks];
                                  n[idx].items = nItems;
                                  update({...d, tasks: n, backgroundUrl: undefined, altText: undefined, items: undefined, zones: undefined});
                              }} onRemove={iId => {
                                  const n = [...tasks];
                                  n[idx].items = n[idx].items.filter(i => i.id !== iId);
                                  update({...d, tasks: n, backgroundUrl: undefined, altText: undefined, items: undefined, zones: undefined});
                              }} labelFn={i => i.type === 'image' ? 'Bilde' : i.content} renderContent={(itm, iIdx) => (
                                  <div className="space-y-3">
                                      <div className="flex gap-2 text-xs mb-2">
                                          <button onClick={() => {
                                              const n = [...tasks];
                                              n[idx].items[iIdx].type = 'text'; 
                                              n[idx].items[iIdx].content = ''; 
                                              update({...d, tasks: n, backgroundUrl: undefined, altText: undefined, items: undefined, zones: undefined});
                                          }} className={`flex-1 py-1.5 rounded-md font-bold transition-colors ${itm.type !== 'image' ? 'bg-cyan-100 text-cyan-800' : 'bg-slate-50 text-slate-500 hover:bg-slate-100'}`}>Tekst</button>
                                          <button onClick={() => {
                                              const n = [...tasks];
                                              n[idx].items[iIdx].type = 'image'; 
                                              n[idx].items[iIdx].content = ''; 
                                              update({...d, tasks: n, backgroundUrl: undefined, altText: undefined, items: undefined, zones: undefined});
                                          }} className={`flex-1 py-1.5 rounded-md font-bold transition-colors ${itm.type === 'image' ? 'bg-cyan-100 text-cyan-800' : 'bg-slate-50 text-slate-500 hover:bg-slate-100'}`}>Bilde</button>
                                      </div>

                                      {itm.type === 'image' ? (
                                           <label className="flex flex-col items-center gap-2 p-4 border-2 border-dashed border-slate-200 rounded-lg cursor-pointer hover:bg-slate-50 hover:border-cyan-300 transition-colors">
                                               {itm.content ? <img src={itm.content} className="h-20 object-contain" /> : <Upload size={20} className="text-slate-400"/>}
                                               <span className="text-xs font-bold text-slate-500">Velg bilde</span>
                                               <input type="file" className="hidden" accept="image/*" onChange={e => upload(e.target.files[0], res => {
                                                   const n = [...tasks];
                                                   n[idx].items[iIdx].content = res; 
                                                   update({...d, tasks: n, backgroundUrl: undefined, altText: undefined, items: undefined, zones: undefined});
                                               }, 'image')} />
                                           </label>
                                      ) : (
                                           <input value={itm.content} onChange={e => {
                                               const n = [...tasks];
                                               n[idx].items[iIdx].content = e.target.value; 
                                               update({...d, tasks: n, backgroundUrl: undefined, altText: undefined, items: undefined, zones: undefined});
                                           }} className={inputClass} placeholder="Tekst..." />
                                      )}

                                      <div>
                                          <label className={labelClass}>Korrekt Sone</label>
                                          <select value={itm.correctZoneId || ''} onChange={e => {
                                              const n = [...tasks];
                                              n[idx].items[iIdx].correctZoneId = e.target.value; 
                                              update({...d, tasks: n, backgroundUrl: undefined, altText: undefined, items: undefined, zones: undefined});
                                          }} className={inputClass}>
                                              <option value="">-- Ingen (kan ikke plasseres) --</option>
                                              {(task.zones||[]).map(z => <option key={z.id} value={z.id}>{z.label}</option>)}
                                          </select>
                                      </div>
                                  </div>
                              )} />
                              <button onClick={() => {
                                  const n = [...tasks];
                                  n[idx].items = [...(n[idx].items||[]), {id: Date.now(), type: 'text', content: ''}];
                                  update({...d, tasks: n, backgroundUrl: undefined, altText: undefined, items: undefined, zones: undefined});
                              }} className="w-full py-2 text-xs font-bold text-cyan-700 bg-cyan-50 rounded-lg hover:bg-cyan-100 mt-3">+ Nytt element</button>
                          </div>
                      </div>
                  </div>
              )} 
          />

          <button 
              onClick={() => update({...d, tasks: [...tasks, {id: Date.now(), backgroundUrl: '', altText: '', items: [], zones: []}], backgroundUrl: undefined, altText: undefined, items: undefined, zones: undefined})} 
              className="w-full py-3 border-2 border-dashed border-cyan-200 bg-cyan-50/50 text-cyan-700 rounded-xl hover:bg-cyan-100 hover:border-cyan-300 transition-all flex items-center justify-center gap-2 font-bold"
          >
              <Plus size={18}/> Legg til oppgave
          </button>
      </div>
    );
  };

  const renderMemory = (d, update) => (
    <div className="space-y-6">
        {/* ... same as before ... */}
        <div className="bg-slate-50 border border-slate-200 p-4 rounded-xl">
            <div className="flex justify-between items-center mb-4">
                <h5 className="font-bold text-slate-700">Kortpar</h5>
                <span className="text-xs text-slate-500">{(d.cards||[]).length / 2} par totalt</span>
            </div>
            <SortableList items={d.cards || []} listKey="memory" onUpdate={n => update({...d, cards: n})} onRemove={id => update({...d, cards: d.cards.filter(c=>c.id!==id)})} labelFn={c => `Par ${c.pairId}: ${c.content}`} renderContent={(c, idx) => (
                <div className="flex gap-3 items-end">
                    <div className="flex-1">
                        <label className={labelClass}>Innhold (Tekst eller Emoji)</label>
                        <input value={c.content} onChange={e => {const n = [...d.cards]; n[idx].content = e.target.value; update({...d, cards: n})}} className={`flex-1 ${inputClass}`} />
                    </div>
                    <div className="w-20 text-center pb-3">
                        <span className="text-xs font-bold text-cyan-600 bg-cyan-100 px-2 py-1 rounded">ID: {c.pairId}</span>
                    </div>
                </div>
            )} />
        </div>
        <button onClick={() => {
            const maxPairId = (d.cards || []).reduce((max, card) => Math.max(max, card.pairId || 0), 0);
            const pairId = maxPairId + 1;
            update({...d, cards: [...(d.cards||[]), {id: Date.now(), content: '', pairId}, {id: Date.now()+1, content: '', pairId}]})
        }} className="w-full py-3 border-2 border-dashed border-cyan-200 bg-cyan-50/50 text-cyan-700 rounded-xl hover:bg-cyan-100 hover:border-cyan-300 transition-all flex items-center justify-center gap-2 font-bold"><Plus size={18}/> Legg til nytt par</button>
    </div>
  );

  const renderTrueFalse = (d, update) => {
      // ... same as before ...
      const questions = d.questions || (d.question ? [{id: 'legacy', question: d.question, isTrue: d.isTrue}] : []);

      return (
          <div className="space-y-6">
              <SortableList 
                  items={questions} 
                  listKey="tf-questions" 
                  onUpdate={n => update({...d, questions: n, question: undefined, isTrue: undefined})} 
                  onRemove={id => update({...d, questions: questions.filter(q => q.id !== id)})}
                  labelFn={(q, i) => `Påstand ${i+1}`}
                  renderContent={(q, idx) => (
                      <div className="space-y-4">
                          <div>
                             <label className={labelClass}>Påstand</label>
                             <textarea 
                                className={`w-full text-sm font-medium ${inputClass}`} 
                                rows={2} 
                                value={q.question} 
                                onChange={e => {
                                    const n = [...questions]; 
                                    n[idx].question = e.target.value; 
                                    update({...d, questions: n, question: undefined, isTrue: undefined});
                                }} 
                                placeholder="Skriv en påstand..." 
                             />
                          </div>
                          <div>
                             <label className={labelClass}>Er påstanden sann?</label>
                             <div className="flex gap-4 mt-2">
                              <button 
                                onClick={() => {const n = [...questions]; n[idx].isTrue = true; update({...d, questions: n})}} 
                                className={`flex-1 py-2 border rounded-lg font-bold transition-all flex items-center justify-center gap-2 ${q.isTrue ? 'bg-teal-600 text-white border-teal-600 ring-2 ring-teal-200' : 'bg-white text-slate-600 border-slate-200 hover:border-cyan-400'}`}
                              >
                                <CheckCircle2 size={16}/> Sant
                              </button>
                              <button 
                                onClick={() => {const n = [...questions]; n[idx].isTrue = false; update({...d, questions: n})}} 
                                className={`flex-1 py-2 border rounded-lg font-bold transition-all flex items-center justify-center gap-2 ${!q.isTrue ? 'bg-red-600 text-white border-red-600 ring-2 ring-red-200' : 'bg-white text-slate-600 border-slate-200 hover:border-cyan-400'}`}
                              >
                                <X size={16}/> Usant
                              </button>
                             </div>
                          </div>
                      </div>
                  )}
              />

              <button 
                  onClick={() => update({...d, questions: [...questions, {id: Date.now(), question: '', isTrue: true}], question: undefined, isTrue: undefined})} 
                  className="w-full py-3 border-2 border-dashed border-cyan-200 bg-cyan-50/50 text-cyan-700 rounded-xl hover:bg-cyan-100 hover:border-cyan-300 transition-all flex items-center justify-center gap-2 font-bold"
              >
                  <Plus size={18}/> Legg til påstand
              </button>
          </div>
      );
  };

  const renderCloze = (d, update) => {
      // ... same as before ...
      const blocks = d.blocks || (d.text ? [{id: 'legacy', text: d.text}] : []);

      return (
          <div className="space-y-4">
              <div className="bg-cyan-50 border border-cyan-200 p-4 rounded-xl text-cyan-900 text-sm mb-4 flex gap-3">
                  <HelpCircle className="flex-shrink-0 mt-0.5" size={18}/>
                  <p>Skriv setninger der ord som skal fylles inn er markert med stjerner. <br/>Eks: "Norges hovedstad er *Oslo*."</p>
              </div>

              <SortableList 
                  items={blocks} 
                  listKey="cloze-blocks" 
                  onUpdate={n => update({...d, blocks: n, text: undefined})} 
                  onRemove={id => update({...d, blocks: blocks.filter(b => b.id !== id)})}
                  labelFn={(b, i) => `Oppgave ${i+1}`}
                  renderContent={(b, idx) => (
                      <textarea 
                          className={`w-full p-4 font-mono text-base leading-loose ${inputClass}`} 
                          rows={4} 
                          value={b.text} 
                          onChange={e => {
                              const n = [...blocks]; 
                              n[idx].text = e.target.value; 
                              update({...d, blocks: n, text: undefined});
                          }} 
                          placeholder="Tekst med *svar*..." 
                      />
                  )}
              />

              <button 
                  onClick={() => update({...d, blocks: [...blocks, {id: Date.now(), text: ''}], text: undefined})} 
                  className="w-full py-3 border-2 border-dashed border-cyan-200 bg-cyan-50/50 text-cyan-700 rounded-xl hover:bg-cyan-100 hover:border-cyan-300 transition-all flex items-center justify-center gap-2 font-bold"
              >
                  <Plus size={18}/> Legg til oppgave
              </button>
          </div>
      );
  };

  const renderMixed = (d, update) => {
      // ... same as before ...
      const options = [
        { label: 'Flervalg', icon: CheckCircle2, color: 'bg-cyan-600' },
        { label: 'Sant/Usant', icon: HelpCircle, color: 'bg-teal-600' },
        { label: 'Fyll inn', icon: Type, color: 'bg-slate-600' },
        { label: 'Bilde Hotspot', icon: MapPin, color: 'bg-rose-500' },
        { label: 'Interaktiv Video', icon: Video, color: 'bg-red-600' },
        { label: 'Tidslinje', icon: CalendarClock, color: 'bg-indigo-600' },
        { label: 'Dra og Slipp', icon: MousePointer2, color: 'bg-amber-600' },
        { label: 'Minnespel', icon: Grid, color: 'bg-pink-600' },
      ];

      return (
      <div className="space-y-8">
          <SortableList items={d.items || []} listKey="mixed" onUpdate={n => update({...d, items: n})} onRemove={id => update({...d, items: d.items.filter(i=>i.id!==id)})} labelFn={i => i.type} renderContent={(item, idx) => (
                <div className="pt-2">
                    {item.type === 'Flervalg' && renderFlervalg(item.data, nd => {const n = [...d.items]; n[idx] = { ...n[idx], data: nd }; update({...d, items: n})})}
                    {item.type === 'Bilde Hotspot' && renderHotspot(item.data, nd => {const n = [...d.items]; n[idx] = { ...n[idx], data: nd }; update({...d, items: n})})}
                    {item.type === 'Interaktiv Video' && renderVideo(item.data, nd => {const n = [...d.items]; n[idx] = { ...n[idx], data: nd }; update({...d, items: n})})}
                    {item.type === 'Tidslinje' && renderTimeline(item.data, nd => {const n = [...d.items]; n[idx] = { ...n[idx], data: nd }; update({...d, items: n})})}
                    {item.type === 'Dra og Slipp' && renderDragDrop(item.data, nd => {const n = [...d.items]; n[idx] = { ...n[idx], data: nd }; update({...d, items: n})})}
                    {item.type === 'Minnespel' && renderMemory(item.data, nd => {const n = [...d.items]; n[idx] = { ...n[idx], data: nd }; update({...d, items: n})})}
                    {item.type === 'Sant/Usant' && renderTrueFalse(item.data, nd => {const n = [...d.items]; n[idx] = { ...n[idx], data: nd }; update({...d, items: n})})}
                    {item.type === 'Fyll inn' && renderCloze(item.data, nd => {const n = [...d.items]; n[idx] = { ...n[idx], data: nd }; update({...d, items: n})})}
                </div>
          )} />

          <div className="bg-slate-50 p-6 rounded-xl border border-slate-200">
              <h4 className="text-xs font-bold text-slate-400 uppercase text-center mb-4 tracking-widest">Legg til ny deloppgave</h4>
              <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-3">
                  {options.map(t => (
                      <button key={t.label} onClick={() => update({...d, items: [...(d.items||[]), {id: Date.now(), type: t.label, data: getDefaultData(t.label)}]})} className="p-3 border border-slate-200 bg-white rounded-xl hover:border-cyan-300 hover:shadow-md text-xs font-bold text-slate-600 flex flex-col items-center justify-center gap-2 transition-all active:scale-95 group h-24">
                          <div className={`w-8 h-8 ${t.color} rounded-lg flex items-center justify-center shadow-sm group-hover:scale-110 transition-transform`}>
                              <t.icon size={16} className="text-white" />
                          </div>
                          <span>{t.label}</span>
                      </button>
                  ))}
              </div>
          </div>
      </div>
      );
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 animate-in slide-in-from-right-8 duration-500 pb-12">
      <div className="lg:col-span-1 space-y-6">
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm sticky top-24">
          <div className="mb-6">
             <label className={labelClass}>Tittel</label>
             <input type="text" value={title} onChange={(e) => setTitle(e.target.value)} className="w-full text-lg font-bold text-slate-800 border-b-2 border-slate-100 focus:border-cyan-500 outline-none pb-2 bg-transparent transition-colors" placeholder="Gi aktiviteten et navn..." />
          </div>
          <div className="mb-6">
             <label className={labelClass}>Beskrivelse (Valgfritt)</label>
             <textarea value={description} onChange={(e) => setDescription(e.target.value)} className={`${inputClass} resize-none`} rows={3} placeholder="Kort om hva studentene skal lære..." />
          </div>

          <div className="flex flex-col gap-3">
            <button onClick={handleSave} className="w-full py-3 bg-cyan-700 hover:bg-cyan-800 text-white rounded-xl font-bold flex items-center justify-center gap-2 transition-all active:scale-95 shadow-md shadow-cyan-100">{saved ? <CheckCircle2 size={20} /> : <Save size={20} />} {saved ? 'Lagret!' : 'Lagre endringer'}</button>
            <button onClick={() => { handleSave(); onPreview(); }} className="w-full py-3 bg-white border border-slate-200 hover:bg-slate-50 text-slate-700 rounded-xl font-bold flex items-center justify-center gap-2 transition-colors"><Eye size={20} /> Forhåndsvisning</button>
          </div>

          <div className="mt-6 pt-6 border-t border-slate-100">
             <div className="bg-blue-50 p-4 rounded-xl border border-blue-100">
               <h4 className="font-bold text-blue-800 mb-2 text-xs uppercase flex items-center gap-2"><HelpCircle size={14}/> Tips</h4>
               <p className="text-xs text-blue-700 leading-relaxed">Endringer lagres automatisk i nettleseren din, men husk å eksportere backup fra hovedmenyen hvis du bytter maskin.</p>
             </div>
          </div>
        </div>
      </div>

      <div className="lg:col-span-2 bg-white rounded-2xl border border-slate-200 shadow-sm p-8 min-h-[600px]">
        <div className="flex justify-between items-center mb-8 border-b border-slate-100 pb-4">
             <h2 className="text-xl font-bold text-slate-800">Innhold</h2>
             <span className="text-xs font-bold text-white bg-slate-400 px-3 py-1 rounded-full uppercase tracking-wider">{activity.type}</span>
        </div>
        {activity.type === 'Flervalg' && renderFlervalg(data, setData)}
        {activity.type === 'Sant/Usant' && renderTrueFalse(data, setData)}
        {activity.type === 'Fyll inn' && renderCloze(data, setData)}
        {activity.type === 'Bilde Hotspot' && renderHotspot(data, setData)}
        {activity.type === 'Interaktiv Video' && renderVideo(data, setData)}
        {activity.type === 'Tidslinje' && renderTimeline(data, setData)}
        {activity.type === 'Dra og Slipp' && renderDragDrop(data, setData)}
        {activity.type === 'Minnespel' && renderMemory(data, setData)}
        {activity.type === 'Flere saman' && renderMixed(data, setData)}
      </div>
    </div>
  );
}

// --- PLAYER COMPONENTS ---

function Player({ activity, onEdit }) {
  const [started, setStarted] = useState(false);

  const renderActivity = (type, data) => {
    switch (type) {
        case 'Flervalg': return <MCPlayer data={data} />;
        case 'Sant/Usant': return <TFPlayer data={data} />;
        case 'Fyll inn': return <ClozePlayer data={data} />;
        case 'Bilde Hotspot': return <HotspotPlayer data={data} />;
        case 'Interaktiv Video': return <VideoPlayer data={data} />;
        case 'Tidslinje': return <TimelinePlayer data={data} />;
        case 'Dra og Slipp': return <DragDropPlayer data={data} />;
        case 'Minnespel': return <MemoryPlayer data={data} />;
        case 'Flere saman': return <MixedPlayer data={data} />;
        default: return <div>Ukjent aktivitet</div>;
    }
  };

  return (
    <div className="max-w-4xl mx-auto animate-in zoom-in-95 duration-500 pb-12">
      <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-slate-200">
        <div className="bg-slate-800 text-white p-8 flex flex-col md:flex-row justify-between items-start md:items-center relative overflow-hidden gap-4">
          <div className="absolute top-0 right-0 opacity-5 transform translate-x-10 -translate-y-10 pointer-events-none">
             <Hexagon size={200} fill="currentColor" stroke="none"/>
          </div>
          <div className="relative z-10">
            <h2 className="text-3xl font-bold mb-2">{activity.title}</h2>
            {activity.description && <p className="text-slate-300 text-sm max-w-xl leading-relaxed opacity-90">{activity.description}</p>}
            {!activity.description && <p className="text-cyan-400 text-xs font-bold uppercase tracking-widest">{activity.type}</p>}
          </div>
          <button onClick={onEdit} className="relative z-10 text-xs font-bold bg-slate-700 hover:bg-slate-600 border border-slate-600 text-white px-4 py-2 rounded-lg transition-colors flex items-center gap-2">
            <Edit3 size={14}/> Rediger
          </button>
        </div>
        <div className="p-8 min-h-[400px] flex flex-col items-center justify-center bg-slate-50/50">
           {!started ? (
             <div className="text-center max-w-md">
               <div className="w-24 h-24 bg-white border-4 border-cyan-50 text-cyan-600 rounded-full flex items-center justify-center mx-auto mb-8 shadow-lg animate-bounce"><Play size={48} fill="currentColor" className="ml-2" /></div>
               <h3 className="text-2xl font-bold text-slate-800 mb-3">Klar til å starte?</h3>
               <p className="text-slate-500 mb-8">Klikk på knappen under for å begynne aktiviteten.</p>
               <button onClick={() => setStarted(true)} className="px-10 py-4 bg-cyan-700 hover:bg-cyan-800 text-white font-bold text-lg rounded-full shadow-xl shadow-cyan-200/50 transition-transform active:scale-95 flex items-center gap-2 mx-auto">
                 Start Aktivitet <ArrowRight size={20}/>
               </button>
             </div>
           ) : (
             <div className="w-full animate-in fade-in duration-500">
               {renderActivity(activity.type, activity.data)}
             </div>
           )}
        </div>
      </div>
    </div>
  );
}

function MixedPlayer({ data }) {
  const [index, setIndex] = useState(0);
  const [stepCompleted, setStepCompleted] = useState(false);
  const [finished, setFinished] = useState(false);
  const [results, setResults] = useState([]); // Accumulate scores/mistakes from each part
  const currentItem = data.items[index];

  useEffect(() => { setStepCompleted(false); }, [index]);

  if (finished) {
      const totalScore = results.reduce((acc, r) => acc + (r.score || 0), 0);
      const totalMax = results.reduce((acc, r) => acc + (r.total || 0), 0);
      const allMistakes = results.flatMap(r => r.mistakes || []);

      return <CompletionScreen onRestart={() => { setFinished(false); setIndex(0); setResults([]); }} score={totalScore} total={totalMax} mistakes={allMistakes} message="Gratulerer!" subMessage="Du har fullført alle deloppgavene." />;
  }

  if (!currentItem) return <div className="text-center text-slate-400 py-12">Ingen innhold å vise.</div>;

  const handleStepSuccess = (res) => {
      setResults(prev => {
          const newResults = [...prev];
          newResults[index] = res || { score: 0, total: 0, mistakes: [] }; // Fallback if undefined
          return newResults;
      });
      setStepCompleted(true);
  };

  const next = () => {
    if (index < data.items.length - 1) setIndex(index + 1);
    else setFinished(true);
  };

  const renderSub = (type, subData) => {
      switch (type) {
        case 'Flervalg': return <MCPlayer data={subData} onSuccess={handleStepSuccess} />;
        case 'Sant/Usant': return <TFPlayer data={subData} onSuccess={handleStepSuccess} />;
        case 'Fyll inn': return <ClozePlayer data={subData} onSuccess={handleStepSuccess} />;
        case 'Bilde Hotspot': return <HotspotPlayer data={subData} onSuccess={handleStepSuccess} />;
        case 'Interaktiv Video': return <VideoPlayer data={subData} onSuccess={handleStepSuccess} />;
        case 'Tidslinje': return <TimelinePlayer data={subData} onSuccess={handleStepSuccess} />;
        case 'Dra og Slipp': return <DragDropPlayer data={subData} onSuccess={handleStepSuccess} />;
        case 'Minnespel': return <MemoryPlayer data={subData} onSuccess={handleStepSuccess} />;
        default: return null;
      }
  };

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-center border-b border-slate-200 pb-4">
        <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">Del {index + 1} av {data.items.length}</span>
        <div className="flex items-center gap-2">
            <span className={`w-2 h-2 rounded-full ${stepCompleted ? 'bg-green-500' : 'bg-slate-300'}`}></span>
            <span className="text-xs font-bold text-cyan-700 uppercase tracking-widest">{currentItem.type}</span>
        </div>
      </div>

      <div className="py-4 relative min-h-[300px]">
          {renderSub(currentItem.type, currentItem.data)}
          {!stepCompleted && <div className="absolute -top-2 -right-2"><Lock size={20} className="text-slate-300 opacity-50" title="Du må fullføre før du kan gå videre" /></div>}
      </div>

      <div className="flex justify-between pt-8 border-t border-slate-200">
        <button onClick={() => setIndex(Math.max(0, index - 1))} disabled={index === 0} className="px-6 py-2 text-slate-500 font-bold hover:bg-slate-100 rounded-lg disabled:opacity-30 transition-colors flex items-center gap-2"><ChevronLeft size={18}/> Forrige</button>
        <div className="flex flex-col items-end">
            <button onClick={next} disabled={!stepCompleted} className="px-8 py-3 bg-slate-800 text-white rounded-xl hover:bg-slate-700 flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed transition-all font-bold shadow-lg">
                {index === data.items.length - 1 ? 'Fullfør' : 'Neste'} <ChevronRight size={18}/>
            </button>
            {!stepCompleted && <span className="text-[10px] text-red-400 mt-2 font-bold uppercase tracking-wide animate-pulse">Løs oppgaven for å gå videre</span>}
        </div>
      </div>
    </div>
  );
}

function VideoPlayer({ data, onSuccess }) {
  const scenes = useMemo(() => data.scenes || (data.videoUrl ? [{id: 'legacy', videoUrl: data.videoUrl, interactions: data.interactions}] : []), [data]);

  const [currentIndex, setCurrentIndex] = useState(0);
  const [finished, setFinished] = useState(false);
  const [completedInteractions, setCompletedInteractions] = useState([]); // Track IDs
  const [sceneResults, setSceneResults] = useState({}); // Map of interaction ID to result object

  const videoRef = useRef(null);
  const [activeInteraction, setActiveInteraction] = useState(null);
  const [showHotspotContent, setShowHotspotContent] = useState(false);
  const [videoEnded, setVideoEnded] = useState(false);

  const currentScene = scenes[currentIndex];

  // Reset state when changing scene, but keep results if we want to sum them up across scenes
  // actually we probably want to accumulate results across all scenes if we have multiple videos
  useEffect(() => {
      setCompletedInteractions([]);
      setVideoEnded(false);
      setActiveInteraction(null);
      setShowHotspotContent(false);
  }, [currentIndex]);

  const handleTimeUpdate = () => {
    if (!videoRef.current || activeInteraction) return;
    const currentTime = Math.floor(videoRef.current.currentTime);
    const interaction = (currentScene.interactions || []).find(i => 
        parseInt(i.time) === currentTime && !completedInteractions.includes(i.id)
    );
    if (interaction) {
        videoRef.current.pause();
        setActiveInteraction(interaction);
        if(interaction.useHotspot) {
            setShowHotspotContent(false);
        } else {
            setShowHotspotContent(true);
        }
    }
  };

  const handleSeeking = () => {
    if (!videoRef.current) return;
    if (activeInteraction) return; 
    const currentTime = videoRef.current.currentTime;
  };

  const handleInteractionComplete = (result) => {
    if (activeInteraction) {
        setCompletedInteractions(prev => [...prev, activeInteraction.id]);
        // Store result for final tally. Default to empty if not provided (some players might not send it yet)
        setSceneResults(prev => ({
            ...prev,
            [activeInteraction.id]: result || { score: 0, total: 0, mistakes: [] }
        }));
        setActiveInteraction(null);
        setShowHotspotContent(false);
        videoRef.current.play();
    }
  };

  const handleEnded = () => {
      setVideoEnded(true);
  };

  const next = () => {
      if (currentIndex < scenes.length - 1) {
          setCurrentIndex(prev => prev + 1);
      } else {
          setFinished(true);
      }
  };

  if (finished) {
      // Aggregate all results
      const allResults = Object.values(sceneResults);
      const totalScore = allResults.reduce((acc, r) => acc + (r.score || 0), 0);
      const totalMax = allResults.reduce((acc, r) => acc + (r.total || 0), 0);
      const allMistakes = allResults.flatMap(r => r.mistakes || []);
      const isPerfect = totalScore === totalMax;

      // If called from mixed player, pass results up. If standalone, show completion.
      if (!onSuccess) return <CompletionScreen onRestart={() => { setFinished(false); setCurrentIndex(0); setSceneResults({}); }} score={totalScore} total={totalMax} mistakes={allMistakes} isPerfect={isPerfect} />;

      return (
          <div className="text-center space-y-6 py-8 bg-white rounded-xl border border-slate-100 animate-in fade-in">
              <div className={`w-16 h-16 rounded-full flex items-center justify-center mx-auto ${isPerfect ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}>
                  {isPerfect ? <CheckCircle2 size={32}/> : <X size={32}/>}
              </div>
              <div>
                  <h3 className="text-xl font-bold text-slate-800">Video ferdig!</h3>
                  <p className="text-slate-500">Score: {totalScore}/{totalMax}</p>
              </div>

              {isPerfect ? (
                  <button onClick={() => onSuccess({ score: totalScore, total: totalMax, mistakes: allMistakes })} className="px-8 py-3 bg-green-600 text-white rounded-xl font-bold hover:bg-green-700 shadow-lg">Fortsett</button>
              ) : (
                  <div>
                      <p className="text-red-500 font-bold mb-4 text-sm">Du må ha alt riktig for å fullføre aktiviteten.</p>
                      <button onClick={() => { setFinished(false); setCurrentIndex(0); setSceneResults({}); }} className="px-8 py-3 bg-slate-700 text-white rounded-xl font-bold hover:bg-slate-800 flex items-center gap-2 mx-auto"><RotateCw size={16}/> Start på nytt</button>
                  </div>
              )}
          </div>
      );
  }

  if (!currentScene) return <div>Ingen video.</div>;

  const ActiveInteractionPlayer = activeInteraction ? (activeInteraction.type === 'Flervalg' ? MCPlayer : (activeInteraction.type === 'Sant/Usant' ? TFPlayer : ClozePlayer)) : null;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center border-b border-slate-100 pb-2">
          <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">Video {currentIndex + 1} av {scenes.length}</span>
      </div>

      <div className="space-y-4 relative">
        <video ref={videoRef} controls={!activeInteraction} src={currentScene.videoUrl} className="w-full rounded-2xl shadow-2xl bg-black aspect-video" onTimeUpdate={handleTimeUpdate} onSeeking={handleSeeking} onEnded={handleEnded} />

        {activeInteraction && activeInteraction.useHotspot && !showHotspotContent && (
            <div className="absolute inset-0 z-10">
                <button 
                  onClick={() => setShowHotspotContent(true)}
                  style={{ 
                      top: `${activeInteraction.y || 50}%`, 
                      left: `${activeInteraction.x || 50}%` 
                  }}
                  className="absolute -ml-6 -mt-6 w-12 h-12 bg-cyan-600 text-white rounded-full flex items-center justify-center shadow-lg animate-bounce hover:scale-110 transition-transform z-20 border-4 border-white/50"
                >
                    <Plus size={24} strokeWidth={3} />
                </button>
                <div className="absolute inset-0 bg-black/20 flex items-end justify-center pb-8 pointer-events-none">
                    <span className="bg-black/70 text-white px-4 py-2 rounded-full text-sm font-bold">Klikk på markøren for å fortsette</span>
                </div>
            </div>
        )}

        {activeInteraction && showHotspotContent && (
          <div className="absolute inset-0 bg-black/80 z-20 flex items-center justify-center p-4 backdrop-blur-sm rounded-2xl animate-in fade-in">
              <div className="bg-white p-8 rounded-2xl w-full max-w-4xl shadow-2xl animate-in zoom-in-95 max-h-[90%] overflow-y-auto border border-slate-200">
                  <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-6 border-b border-slate-100 pb-2">Video stoppet: Løs oppgave</h4>
                  {ActiveInteractionPlayer && <ActiveInteractionPlayer data={activeInteraction.data} onSuccess={handleInteractionComplete} compact={true} />}
              </div>
          </div>
        )}

        {videoEnded && (
            <div className="text-center space-y-4 py-4 bg-green-50 rounded-xl border border-green-100 animate-in fade-in">
                <div className="text-green-700 font-bold flex items-center justify-center gap-2"><CheckCircle2/> Video ferdigspilt!</div>
                <button onClick={next} className="px-6 py-2 bg-cyan-700 text-white rounded-lg font-bold hover:bg-cyan-800 flex items-center gap-2 mx-auto">
                    {currentIndex < scenes.length - 1 ? 'Neste Video' : 'Fullfør'} <ChevronRight size={18}/>
                </button>
            </div>
        )}
      </div>
    </div>
  );
}

function TimelinePlayer({ data, onSuccess }) {
  const events = React.useMemo(() => {
      return [...(data.events || [])].sort((a, b) => {
          const dateA = parseInt(a.date);
          const dateB = parseInt(b.date);
          if (!isNaN(dateA) && !isNaN(dateB)) return dateA - dateB;
          return a.date.localeCompare(b.date, undefined, { numeric: true });
      });
  }, [data.events]);

  const [activeIndex, setActiveIndex] = useState(0);
  const [finished, setFinished] = useState(false);
  const currentEvent = events[activeIndex];
  const isLast = activeIndex === events.length - 1;

  if (!events.length) return <div>Ingen hendingar.</div>;

  if (finished) {
      if (!onSuccess) return <CompletionScreen onRestart={() => { setFinished(false); setActiveIndex(0); }} />;
      // For mixed player success pass empty result
      return <div className="text-center animate-in fade-in"><button onClick={() => onSuccess({})} className="px-8 py-3 bg-green-600 text-white rounded-xl font-bold">Fortsett</button></div>;
  }

  return (
    <div className="space-y-8">
        <div className="bg-white border border-slate-200 rounded-2xl overflow-hidden shadow-sm flex flex-col md:flex-row min-h-[400px] animate-in fade-in duration-300 key={activeIndex}">
            {currentEvent.imageUrl && (
                <div className="md:w-1/2 bg-slate-100 h-64 md:h-auto relative">
                      <img src={currentEvent.imageUrl} className="w-full h-full object-cover absolute inset-0" />
                </div>
            )}
            <div className={`p-8 md:p-12 flex flex-col justify-center ${currentEvent.imageUrl ? 'md:w-1/2' : 'w-full'}`}>
                <div className="text-cyan-600 font-bold text-2xl mb-3">{currentEvent.date}</div>
                <h3 className="text-3xl font-bold text-slate-800 mb-6 leading-tight">{currentEvent.title}</h3>
                <div className="w-10 h-1 bg-cyan-500 mb-6"></div>
                <p className="text-slate-600 leading-relaxed text-lg">{currentEvent.body}</p>
            </div>
        </div>

        <div className="relative px-6">
            <div className="absolute top-1/2 left-0 right-0 h-1 bg-slate-200 -translate-y-1/2 z-0 rounded-full"></div>
            <div className="relative z-10 flex justify-between items-center overflow-x-auto pb-8 pt-8 hide-scrollbar gap-4 snap-x">
                {events.map((evt, idx) => (
                    <button 
                        key={evt.id} 
                        onClick={() => setActiveIndex(idx)} 
                        className={`flex-shrink-0 flex flex-col items-center gap-2 group outline-none snap-center focus:outline-none`}
                    >
                        <div className={`w-4 h-4 rounded-full transition-all duration-300 ring-4 ${idx === activeIndex ? 'bg-cyan-600 scale-150 ring-cyan-100' : 'bg-slate-300 ring-transparent group-hover:bg-cyan-400'}`} />
                        <span className={`text-xs font-bold transition-colors ${idx === activeIndex ? 'text-cyan-700' : 'text-slate-400 group-hover:text-cyan-600'}`}>{evt.date}</span>
                    </button>
                ))}
            </div>

            <div className="flex justify-between mt-4">
                <button onClick={() => setActiveIndex(Math.max(0, activeIndex - 1))} disabled={activeIndex === 0} className="flex items-center gap-2 px-4 py-2 text-slate-500 disabled:opacity-30 hover:text-cyan-700 hover:bg-slate-100 rounded-lg font-bold transition-colors"><ChevronLeft size={20} /> Forrige</button>
                {isLast ? (
                    <button onClick={() => setFinished(true)} className="px-8 py-2 bg-cyan-700 text-white rounded-xl hover:bg-cyan-800 font-bold shadow-md transition-transform active:scale-95">Fullfør</button>
                ) : (
                    <button onClick={() => setActiveIndex(Math.min(events.length - 1, activeIndex + 1))} className="flex items-center gap-2 px-4 py-2 text-slate-500 hover:text-cyan-700 hover:bg-slate-100 rounded-lg font-bold transition-colors">Neste <ChevronRight size={20} /></button>
                )}
            </div>
        </div>
    </div>
  );
}

function DragDropPlayer({ data, onSuccess }) {
  const tasks = useMemo(() => data.tasks || (data.backgroundUrl ? [{id: 'legacy', backgroundUrl: data.backgroundUrl, altText: data.altText, items: data.items, zones: data.zones}] : []), [data]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [finished, setFinished] = useState(false);

  const [items, setItems] = useState([]);
  const [activeDrag, setActiveDrag] = useState(null);
  const [feedback, setFeedback] = useState(null);
  const [showResults, setShowResults] = useState(false);
  const containerRef = useRef(null);

  const currentTask = tasks[currentIndex];

  useEffect(() => {
    if (currentTask) {
        setItems(currentTask.items ? currentTask.items.map(i => ({ ...i, x: null, y: null })) : []);
        setFeedback(null);
        setShowResults(false);
    }
  }, [currentTask]);

  const startDragFromBench = (e, item) => {
      e.preventDefault();
      const containerRect = containerRef.current.getBoundingClientRect();
      const itemRect = e.currentTarget.getBoundingClientRect();
      const offsetX = e.clientX - itemRect.left;
      const offsetY = e.clientY - itemRect.top;
      const x = ((itemRect.left - containerRect.left) / containerRect.width) * 100;
      const y = ((itemRect.top - containerRect.top) / containerRect.height) * 100;
      setItems(prev => prev.map(i => i.id === item.id ? { ...i, x, y } : i));
      setActiveDrag({ id: item.id, offsetX, offsetY });
  };

  const handleMouseDown = (e, id) => {
    if(showResults) return;
    e.preventDefault();
    const item = items.find(i => i.id === id);
    const rect = e.currentTarget.getBoundingClientRect();
    const offsetX = e.clientX - rect.left;
    const offsetY = e.clientY - rect.top;
    setActiveDrag({ id, offsetX, offsetY, startX: e.clientX, startY: e.clientY });
  };

  const handleMouseMove = (e) => {
    if (!activeDrag) return;
    const containerRect = containerRef.current.getBoundingClientRect();
    const x = ((e.clientX - containerRect.left - activeDrag.offsetX) / containerRect.width) * 100;
    const y = ((e.clientY - containerRect.top - activeDrag.offsetY) / containerRect.height) * 100;
    setItems(prev => prev.map(i => i.id === activeDrag.id ? { ...i, x, y } : i));
  };

  const handleMouseUp = () => {
    setActiveDrag(null);
  };

  const checkAnswer = () => {
    let correctCount = 0;
    const results = items.map(item => {
        if (!item.correctZoneId) return { ...item, isCorrect: true };
        if (item.x === null) return { ...item, isCorrect: false };
        const zone = currentTask.zones.find(z => z.id == item.correctZoneId);
        if (!zone) return { ...item, isCorrect: false };
        const cx = item.x + 5; 
        const cy = item.y + 2.5;
        const inZone = cx >= zone.left && cx <= (zone.left + (zone.width || 15)) && cy >= zone.top && cy <= (zone.top + (zone.height || 10));
        if(inZone) correctCount++;
        return { ...item, isCorrect: inZone };
    });

    setItems(results);
    setShowResults(true);
    const requiredCount = items.filter(i => i.correctZoneId).length;

    if (correctCount === requiredCount) {
        setFeedback({ type: 'success', msg: 'Fantastisk! Alt er riktig plassert.' });
    } else {
        setFeedback({ type: 'error', msg: `Du har plassert ${correctCount} av ${requiredCount} elementer riktig.` });
    }
  };

  const next = () => {
      if (currentIndex < tasks.length - 1) {
          setCurrentIndex(prev => prev + 1);
      } else {
          setFinished(true);
      }
  };

  if (finished) {
      if (!onSuccess) return <CompletionScreen onRestart={() => { setFinished(false); setCurrentIndex(0); }} message="Alle oppgaver fullført!" />;
      return <div className="text-center animate-in fade-in"><button onClick={() => onSuccess({})} className="px-8 py-3 bg-green-600 text-white rounded-xl font-bold">Fortsett</button></div>;
  }

  if(!currentTask) return <div>Laster oppgave...</div>;

  return (
    <div className="space-y-6 select-none" onMouseMove={handleMouseMove} onMouseUp={handleMouseUp}>
      <div className="flex justify-between items-center border-b border-slate-100 pb-2">
          <h4 className="font-bold text-slate-700">Oppgave {currentIndex + 1} av {tasks.length}</h4>
          <button onClick={() => { setItems(currentTask.items.map(i => ({...i, x: null, y: null}))); setFeedback(null); setShowResults(false); }} className="text-sm text-slate-500 hover:text-cyan-700 underline">Nullstill</button>
      </div>

      <div ref={containerRef} className="relative border-2 border-slate-200 rounded-2xl bg-slate-100 min-h-[500px] shadow-inner overflow-hidden">
        <div className="absolute inset-0">
            <img src={currentTask.backgroundUrl} alt={currentTask.altText || "Bakgrunn"} className="w-full h-full object-cover opacity-90 block pointer-events-none" />
            {(currentTask.zones || []).map(z => (
                <div key={z.id} style={{ top: `${z.top}%`, left: `${z.left}%`, width: `${z.width || 15}%`, height: `${z.height || 10}%` }} className="absolute border-2 border-dashed border-slate-500/30 bg-white/20 rounded-lg flex items-center justify-center group">
                    <span className="text-[10px] font-bold text-slate-600 uppercase bg-white/80 px-2 rounded-full opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">{z.label}</span>
                </div>
            ))}
        </div>
        {items.filter(i => i.x !== null).map(i => (
            <div 
                key={i.id} 
                onMouseDown={(e) => handleMouseDown(e, i.id)} 
                style={{ top: `${i.y}%`, left: `${i.x}%`, position: 'absolute', zIndex: activeDrag?.id === i.id ? 50 : 10 }} 
                className={`cursor-grab active:cursor-grabbing shadow-lg transition-transform transform hover:scale-105 ${showResults ? (i.isCorrect ? 'ring-4 ring-green-500' : 'ring-4 ring-red-500') : ''} rounded-lg`}
            >
                {i.type === 'image' ? <img src={i.content} className="w-24 h-24 object-cover rounded-lg border-2 border-white bg-white" draggable={false}/> : <div className="bg-cyan-700 text-white px-4 py-2 rounded-lg text-sm font-bold whitespace-nowrap shadow-md border border-cyan-800">{i.content}</div>}
                {showResults && (
                    <div className={`absolute -top-2 -right-2 rounded-full p-1 text-white ${i.isCorrect ? 'bg-green-500' : 'bg-red-500'}`}>
                        {i.isCorrect ? <CheckCircle2 size={12}/> : <X size={12}/>}
                    </div>
                )}
            </div>
        ))}
      </div>

      <div className="p-6 bg-slate-50 rounded-2xl border border-slate-200 min-h-[120px] flex gap-4 flex-wrap items-center justify-center">
         {items.filter(i => i.x === null).length === 0 && <span className="text-slate-400 text-sm italic">Alle elementer er plassert</span>}
         {items.filter(i => i.x === null).map(i => (
             <div key={i.id} onMouseDown={(e) => startDragFromBench(e, i)} className="cursor-grab hover:scale-105 transition-transform">
                {i.type === 'image' ? <img src={i.content} className="w-20 h-20 object-cover rounded-lg border-2 border-slate-200 bg-white shadow-sm" draggable={false}/> : <div className="bg-white border-2 border-cyan-100 text-cyan-800 px-4 py-2 rounded-lg text-sm font-bold shadow-sm hover:border-cyan-300 hover:shadow-md transition-all">{i.content}</div>}
             </div>
         ))}
      </div>

      <div className="flex justify-center items-center pt-4">
         {feedback && <div className={`mr-6 font-bold text-lg animate-in fade-in slide-in-from-bottom-2 ${feedback.type === 'success' ? 'text-green-600' : 'text-red-600'}`}>{feedback.msg}</div>}
         {!showResults ? (
            <button onClick={checkAnswer} className="px-8 py-3 bg-cyan-700 text-white rounded-xl hover:bg-cyan-800 font-bold shadow-lg shadow-cyan-100 transition-transform active:scale-95">Sjekk Svar</button>
         ) : (
            feedback.type === 'success' && (
                <button onClick={next} className="px-8 py-3 bg-slate-800 text-white rounded-xl hover:bg-slate-700 font-bold shadow-lg flex items-center gap-2">
                    {currentIndex < tasks.length - 1 ? 'Neste Oppgave' : 'Fullfør'} <ChevronRight size={20}/>
                </button>
            )
         )}
      </div>
    </div>
  );
}

function MemoryPlayer({ data, onSuccess }) {
  const [flipped, setFlipped] = useState([]);
  const [matched, setMatched] = useState([]);
  const [cards, setCards] = useState([]);
  const [finished, setFinished] = useState(false);

  useEffect(() => {
    setCards([...data.cards].sort(() => Math.random() - 0.5));
  }, [data]);

  useEffect(() => {
      if (matched.length === data.cards.length && data.cards.length > 0 && onSuccess) {
          // Optional delay
      }
  }, [matched, data.cards.length, onSuccess]);

  const handleCardClick = (idx) => {
    if (flipped.length === 2 || matched.includes(idx) || flipped.includes(idx)) return;
    const newFlipped = [...flipped, idx];
    setFlipped(newFlipped);
    if (newFlipped.length === 2) {
      const id1 = cards[newFlipped[0]].pairId;
      const id2 = cards[newFlipped[1]].pairId;
      if (id1 === id2) {
        setMatched([...matched, ...newFlipped]);
        setFlipped([]);
      } else {
        setTimeout(() => setFlipped([]), 1000);
      }
    }
  };

  const isAllMatched = matched.length === data.cards.length && data.cards.length > 0;

  if (finished && !onSuccess) return <CompletionScreen onRestart={() => { setMatched([]); setFlipped([]); setFinished(false); setCards([...data.cards].sort(() => Math.random() - 0.5)); }} />;

  return (
    <div className="space-y-8">
        <div className="grid grid-cols-4 md:grid-cols-4 gap-4 max-w-3xl mx-auto">
        {cards.map((card, idx) => (
            <div key={card.id} onClick={() => handleCardClick(idx)} className="aspect-square perspective-1000 cursor-pointer group">
                 <div className={`relative w-full h-full transition-all duration-500 transform-style-3d ${flipped.includes(idx) || matched.includes(idx) ? 'rotate-y-180' : ''}`}>
                      {/* FRONT (Hidden) */}
                      <div className={`absolute inset-0 w-full h-full bg-cyan-700 rounded-xl border-b-4 border-cyan-900 flex items-center justify-center shadow-md group-hover:-translate-y-1 transition-transform backface-hidden`}>
                           <Hexagon className="text-cyan-500/30" size={40} fill="currentColor"/>
                      </div>
                      {/* BACK (Revealed) */}
                      <div className="absolute inset-0 w-full h-full bg-white border-2 border-cyan-500 rounded-xl flex items-center justify-center text-xl md:text-3xl font-bold text-cyan-800 shadow-lg rotate-y-180 backface-hidden">
                           {card.content}
                      </div>
                 </div>
            </div>
        ))}
        </div>
        {isAllMatched && (
            <div className="text-center animate-in fade-in slide-in-from-bottom-4">
                <div className="text-green-600 font-bold text-xl mb-4">Alle par funnet!</div>
                <button onClick={() => onSuccess ? onSuccess() : setFinished(true)} className="px-10 py-3 bg-cyan-700 text-white rounded-xl font-bold hover:bg-cyan-800 shadow-lg transition-transform active:scale-95">Fullført</button>
            </div>
        )}
    </div>
  );
}

function HotspotPlayer({ data, onSuccess }) {
  const scenes = useMemo(() => data.scenes || (data.imageUrl ? [{id: 'legacy', imageUrl: data.imageUrl, altText: data.altText, hotspots: data.hotspots}] : []), [data]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [activeSpot, setActiveSpot] = useState(null);
  const [viewedSpots, setViewedSpots] = useState([]); 
  const [finished, setFinished] = useState(false);

  const currentScene = scenes[currentIndex];
  const isSceneFinished = (currentScene.hotspots || []).every(h => viewedSpots.includes(h.id));

  useEffect(() => {
      setViewedSpots([]);
      setActiveSpot(null);
  }, [currentIndex]);

  const handleSpotClick = (id) => {
      setActiveSpot(activeSpot === id ? null : id);
      if (!viewedSpots.includes(id)) {
          setViewedSpots(prev => [...prev, id]);
      }
  };

  const next = () => {
      if (currentIndex < scenes.length - 1) {
          setCurrentIndex(prev => prev + 1);
      } else {
          setFinished(true);
      }
  };

  if (finished) {
      if(!onSuccess) return <CompletionScreen onRestart={() => { setFinished(false); setCurrentIndex(0); }} />;
      return <div className="text-center animate-in fade-in"><button onClick={() => onSuccess({})} className="px-8 py-3 bg-green-600 text-white rounded-xl font-bold">Fortsett</button></div>;
  }

  if (!currentScene) return <div>Ingen bilder funnet.</div>;

  return (
    <div className="space-y-8">
        <div className="flex justify-between items-center border-b border-slate-100 pb-4">
            <h4 className="font-bold text-slate-700">Utforsk bildet ({currentIndex + 1} av {scenes.length})</h4>
            <span className="text-xs bg-slate-100 px-3 py-1 rounded-full font-bold text-slate-500">{viewedSpots.length} av {(currentScene.hotspots||[]).length} funnet</span>
        </div>

        <div className="relative inline-block w-full h-auto rounded-2xl overflow-hidden shadow-2xl border border-slate-200 bg-slate-900 group">
            {currentScene.imageUrl ? (
                <img src={currentScene.imageUrl} alt={currentScene.altText || "Interaktivt Bilde"} className="w-full h-auto block opacity-95 group-hover:opacity-100 transition-opacity" />
            ) : (
                <div className="h-64 flex items-center justify-center text-slate-500">Bilde mangler</div>
            )}

            {(currentScene.hotspots || []).map((hs) => (
                <React.Fragment key={hs.id}>
                <button 
                    onClick={() => handleSpotClick(hs.id)} 
                    style={{ top: `${hs.top}%`, left: `${hs.left}%` }} 
                    className={`absolute w-10 h-10 -ml-5 -mt-5 rounded-full flex items-center justify-center shadow-xl transition-all transform hover:scale-110 z-10 cursor-pointer ${viewedSpots.includes(hs.id) ? 'bg-green-500 text-white' : 'bg-cyan-600 text-white animate-pulse'} ring-4 ring-white/30`}
                >
                    {activeSpot === hs.id ? <X size={20} /> : (viewedSpots.includes(hs.id) ? <CheckCircle2 size={20} /> : <Plus size={24} strokeWidth={3} />)}
                </button>

                {activeSpot === hs.id && (
                    <div style={{ top: `${Math.min(hs.top + 8, 80)}%`, left: `${Math.min(Math.max(hs.left - 15, 5), 65)}%` }} className="absolute w-72 bg-white p-6 rounded-2xl shadow-2xl z-30 animate-in fade-in zoom-in-95 duration-200 origin-top-left border-l-8 border-cyan-600">
                        <h4 className="font-bold text-lg text-slate-800 mb-2">{hs.header}</h4>
                        <p className="text-slate-600 leading-relaxed">{hs.content}</p>
                    </div>
                )}
                </React.Fragment>
            ))}
            {activeSpot && (<div className="absolute inset-0 z-20 bg-black/10" onClick={() => setActiveSpot(null)} />)}
        </div>

        <div className="flex justify-end pt-4">
            {isSceneFinished ? (
                <button onClick={onSuccess && currentIndex === scenes.length - 1 ? onSuccess : next} className="px-8 py-3 bg-slate-800 text-white rounded-xl hover:bg-slate-700 font-bold shadow-lg flex items-center gap-2 transition-transform active:scale-95">
                    {currentIndex < scenes.length - 1 ? 'Neste bilde' : 'Fullfør'} <ChevronRight size={20}/>
                </button>
            ) : (
                <span className="text-sm text-slate-400 font-medium italic flex items-center gap-2"><Lock size={14}/> Finn alle punktene for å gå videre</span>
