import React, { useState } from 'react';
import { 
  CheckCircle2, HelpCircle, Type, MapPin, Video, CalendarClock, MousePointer2, Grid, Layers, 
  Plus, Layout, Play, Edit3, Share2, Copy, Code, X, Download, Wand2, AlertTriangle, Link as LinkIcon
