interface EmbedDialogProps {
  activity: Activity;
  onClose: () => void;
  onDownload: (activity: Activity) => void;
}

const EmbedDialog: React.FC<EmbedDialogProps> = ({ activity, onClose, onDownload }) => {
  const [userUrl, setUserUrl] = useState('');
  const [warning, setWarning] = useState<string | null>(null);

  const handleUrlChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const rawVal = e.target.value;
      setUserUrl(rawVal);
      const val = decodeURIComponent(rawVal);

      // 1. STRICT CHECK FOR PAGES (Cause of Inception)
      if (val.includes('/pages/')) {
          setWarning("STOPP: Dette er en lenke til en SIDE. Det skaper 'vindu-i-vindu'. Gå til 'Filer', høyreklikk filen, og velg 'Kopier lenke'.");
          return;
      } 

      // 2. CHECK FOR CANVAS DOMAIN
      if (val.includes('instructure.com')) {
          // Check if we can find the File ID (digits)
          // We look for 'files' followed eventually by digits, handling various slash/encoding scenarios
          const hasFileId = /\/files\/?\d+/.test(val) || (val.includes('files') && /\d{4,}/.test(val));

          if (!hasFileId) {
               setWarning("Vi klarte ikke å finne Fil-IDen i lenken din. Er du sikker på at du kopierte lenken fra 'Filer'?");
          } else {
               setWarning(null);
          }
      } else if (val.length > 0) {
           setWarning(null);
      }
  };

  // ROBUST RECONSTRUCTION STRATEGY
  const getFixedUrl = (url: string) => {
    if (!url.trim()) return 'URL_TIL_FILEN.html';

    let clean = decodeURIComponent(url.trim());

    // Extract key components using Regex
    const domainMatch = clean.match(/https?:\/\/([^/]+)/);
    const courseMatch = clean.match(/\/courses\/(\d+)/);
    // Matches /files/12345 OR /course_files/12345
    const fileMatch = clean.match(/\/(?:files|course_files)\/(\d+)/);

    // STRATEGY 1: TOTAL RECONSTRUCTION (Best)
    // If we have Domain + CourseID + FileID, we build the perfect URL from scratch.
    // This discards any "download", "preview", or weird query params in the user's link.
    if (domainMatch && courseMatch && fileMatch) {
        const domain = domainMatch[1];
        const courseId = courseMatch[1];
        const fileId = fileMatch[1];
        return `https://${domain}/courses/${courseId}/files/${fileId}/file_preview?annotate=0`;
    }

    // STRATEGY 2: SUFFIX APPEND (Fallback)
    // If we can't fully reconstruct, we try to find the file base path and append the suffix.
    const baseFileMatch = clean.match(/(.*\/files\/\d+)/);
    if (baseFileMatch) {
        return `${baseFileMatch[1]}/file_preview?annotate=0`;
    }

    // STRATEGY 3: BLIND APPEND (Last Resort)
    // If it looks like a Canvas file link but regex failed, try stripping common suffixes and appending ours.
    if (clean.includes('/files/')) {
        let stripped = clean.split('?')[0].split('#')[0];
        if (stripped.endsWith('/download')) stripped = stripped.replace('/download', '');
        if (stripped.endsWith('/preview')) stripped = stripped.replace('/preview', '');
        if (stripped.endsWith('/')) stripped = stripped.slice(0, -1);
        return `${stripped}/file_preview?annotate=0`;
    }

    return clean;
  };

  const fixedUrl = getFixedUrl(userUrl);
  // It is "fixed" if we successfully transformed it into a file_preview URL
  const isFixed = userUrl && fixedUrl !== userUrl && fixedUrl.endsWith('/file_preview?annotate=0');

  // Iframe code with anti-scroll attributes to prevent double scrollbars
  const iframeCode = `<iframe style="width: 100%; height: 800px; overflow: hidden;" scrolling="no" title="${activity.title}" src="${fixedUrl}"></iframe>`;

  return (
     <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 animate-in fade-in">
        <div className="bg-white rounded-2xl p-6 max-w-lg w-full shadow-2xl space-y-6 max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
           <div className="flex justify-between items-start">
