    downloadAnchorNode.setAttribute("download", "hvl_aktiviteter_backup.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const handleImport = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files && event.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        if(typeof e.target?.result === 'string') {
          const imported = JSON.parse(e.target.result);
          if (Array.isArray(imported)) {
            setActivities(prev => {
              const combined = [...prev];
              imported.forEach(newItem => {
                const idx = combined.findIndex(existing => existing.id === newItem.id);
                if (idx >= 0) combined[idx] = newItem;
                else combined.push(newItem);
              });
              return combined;
            });
            alert(`Importerte ${imported.length} aktiviteter.`);
          } else {
            alert("Ugyldig filformat.");
          }
        }
      } catch (error) {
        console.error(error);
        alert("Kunne ikke lese filen.");
      }
    };
    reader.readAsText(file);
  };

  return (
