           Canvas kan blokkere opplastede bilder. Prøv ekstern URL (https://) istedenfor.
        </span>
      </div>
    );
  }
  return <img src={src} alt={alt || "Interaktivt bilde"} className={className} style={style} onError={() => setError(true)} />;
};

export const HotspotPlayer: React.FC<PlayerProps> = ({ data, onSuccess }) => {
  const scenes = useMemo(() => {
    if (data.scenes && data.scenes.length > 0) return data.scenes;
    if (data.imageUrl) return [{ id: 'legacy', imageUrl: data.imageUrl, altText: data.altText, hotspots: data.hotspots || [] }];
    return [];
  }, [data]);

  const [currentIndex, setCurrentIndex] = useState(0);
  const [activeSpot, setActiveSpot] = useState<number | string | null>(null);
  const [viewedSpots, setViewedSpots] = useState<(number | string)[]>([]); 
  const [finished, setFinished] = useState(false);

  const currentScene = scenes[currentIndex];
  const isSceneFinished = useMemo(() => {
    if (!currentScene || !currentScene.hotspots) return true;
    return currentScene.hotspots.every((h: any) => viewedSpots.includes(h.id));
  }, [currentScene, viewedSpots]);

  useEffect(() => {
      setViewedSpots([]);
      setActiveSpot(null);
  }, [currentIndex]);

  const handleSpotClick = (id: number | string) => {
      setActiveSpot(activeSpot === id ? null : id);
      if (!viewedSpots.includes(id)) {
          setViewedSpots(prev => [...prev, id]);
      }
  };

  const next = () => {
      if (currentIndex < scenes.length - 1) {
          setCurrentIndex(prev => prev + 1);
      } else {
          setFinished(true);
      }
  };

  if (finished) {
      if(!onSuccess) return <CompletionScreen onRestart={() => { setFinished(false); setCurrentIndex(0); }} />;
      return <div className="text-center animate-in fade-in"><button onClick={() => onSuccess && onSuccess({})} className="px-8 py-3 bg-green-600 text-white rounded-xl font-bold">Fortsett</button></div>;
  }

  if (!currentScene) return <div className="p-12 text-center text-slate-400">Ingen bilder funnet i denne aktiviteten.</div>;

  return (
    <article className="space-y-8">
        <header className="flex justify-between items-center border-b border-slate-100 pb-4">
            <h4 className="font-bold text-slate-700">Utforsk bildet ({currentIndex + 1} av {scenes.length})</h4>
            <span className="text-xs bg-slate-100 px-3 py-1 rounded-full font-bold text-slate-500" role="status" aria-live="polite">
              {viewedSpots.length} av {(currentScene.hotspots||[]).length} funnet
            </span>
        </header>

        <div className="relative inline-block w-full h-auto rounded-2xl overflow-hidden shadow-2xl border border-slate-200 bg-slate-900 group">
            {currentScene.imageUrl ? (
                <SafeImage src={currentScene.imageUrl} alt={currentScene.altText || "Interaktivt Bilde"} className="w-full h-auto block opacity-95 group-hover:opacity-100 transition-opacity" />
            ) : (
                <div className="h-64 flex items-center justify-center text-slate-500">Bilde mangler eller er ikke lastet opp.</div>
            )}

            {(currentScene.hotspots || []).map((hs: any) => (
                <React.Fragment key={hs.id}>
                <button 
                    onClick={() => handleSpotClick(hs.id)} 
                    style={{ top: `${hs.top}%`, left: `${hs.left}%` }} 
                    className={`absolute w-10 h-10 -ml-5 -mt-5 rounded-full flex items-center justify-center shadow-xl transition-all transform hover:scale-110 z-10 cursor-pointer ${viewedSpots.includes(hs.id) ? 'bg-green-500 text-white' : 'bg-cyan-600 text-white animate-pulse'} ring-4 ring-white/30`}
                    aria-label={`Hotspot: ${hs.header}`}
                    aria-expanded={activeSpot === hs.id}
                >
                    {activeSpot === hs.id ? <X size={20} aria-hidden="true" /> : (viewedSpots.includes(hs.id) ? <CircleCheck size={20} aria-hidden="true" /> : <Plus size={24} strokeWidth={3} aria-hidden="true" />)}
                </button>

                {activeSpot === hs.id && (
                    <section 
                      style={{ top: `${Math.min(hs.top + 8, 80)}%`, left: `${Math.min(Math.max(hs.left - 15, 5), 65)}%` }} 
                      className="absolute w-72 bg-white p-6 rounded-2xl shadow-2xl z-30 animate-in fade-in zoom-in-95 duration-200 origin-top-left border-l-8 border-cyan-600"
                    >
                        <h5 className="font-bold text-lg text-slate-800 mb-2">{hs.header}</h5>
                        <p className="text-slate-600 leading-relaxed">{hs.content}</p>
                    </section>
                )}
                </React.Fragment>
            ))}
            {activeSpot && (<div className="absolute inset-0 z-20 bg-black/10" onClick={() => setActiveSpot(null)} aria-hidden="true" />)}
        </div>

        <footer className="flex justify-end pt-4">
            {isSceneFinished ? (
                <button 
                  onClick={() => {
                    if (currentIndex === scenes.length - 1) {
                        if (onSuccess) onSuccess({});
                        else setFinished(true);
                    } else {
                        next();
                    }
                }} className="px-8 py-3 bg-slate-800 text-white rounded-xl hover:bg-slate-700 font-bold shadow-lg flex items-center gap-2 transition-transform active:scale-95">
                    {currentIndex < scenes.length - 1 ? 'Neste bilde' : 'Fullfør'} <ChevronRight size={20} aria-hidden="true"/>
                </button>
            ) : (
                <span className="text-sm text-slate-400 font-medium italic flex items-center gap-2" role="status">
                  <Lock size={14} aria-hidden="true"/> Finn alle punktene for å gå videre
                </span>
            )}
        </footer>
    </article>
  );
};

import React, { useState } from 'react';
import { 
  CircleCheck, CircleHelp, Type, MapPin, Video, CalendarClock, 
  MousePointer2, Grid, Layers, Plus, Layout, Play, Pencil, 
  Code, Share2, Copy 
} from 'lucide-react';
import { Activity } from '../types';
import { DeleteButton } from './ui/DeleteButton';

// Mock/Placeholder for EmbedDialog as it was referenced but not provided in full context
const EmbedDialog = ({ activity, onClose, onDownload }: any) => (
  <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/50 backdrop-blur-sm animate-in fade-in">
    <div className="bg-white rounded-[2rem] p-10 max-w-2xl w-full shadow-2xl">
      <h2 className="text-3xl font-bold mb-4">Bygg inn {activity.title}</h2>
      <p className="text-slate-600 mb-6 text-lg">Bruk HTML-eksport for å legge denne aktiviteten inn i Canvas eller andre plattformer.</p>
      <div className="flex gap-4">
        <button onClick={() => onDownload(activity)} className="flex-1 py-4 bg-cyan-700 text-white rounded-xl font-bold text-xl hover:bg-cyan-800 transition-colors">Last ned HTML</button>
        <button onClick={onClose} className="px-8 py-4 bg-slate-100 text-slate-600 rounded-xl font-bold text-xl hover:bg-slate-200 transition-colors">Lukk</button>
      </div>
    </div>
  </div>
);

interface DashboardProps {
  activities: Activity[];
  onCreate: (type: string) => void;
  onEdit: (activity: Activity) => void;
  onPlay: (activity: Activity) => void;
  onDelete: (id: string) => void;
  onDuplicate: (activity: Activity) => void;
  onExport: () => void;
  onImport: (event: React.ChangeEvent<HTMLInputElement>) => void;
  onDownloadHTML: (activity: Activity) => void;
  isDeepLinking?: boolean;
  onSelect?: (activity: Activity) => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ activities, onCreate, onEdit, onPlay, onDelete, onDuplicate, onExport, onImport, onDownloadHTML, isDeepLinking = false, onSelect }) => {
  const [embedActivity, setEmbedActivity] = useState<Activity | null>(null);

  const types = [
    { label: 'Flervalg', icon: CircleCheck, color: 'bg-cyan-600' },
    { label: 'Sant/Usant', icon: CircleHelp, color: 'bg-teal-600' },
    { label: 'Fyll inn', icon: Type, color: 'bg-slate-600' },
    { label: 'Bilde Hotspot', icon: MapPin, color: 'bg-rose-500' },
    { label: 'Interaktiv Video', icon: Video, color: 'bg-red-600' },
    { label: 'Tidslinje', icon: CalendarClock, color: 'bg-indigo-600' },
    { label: 'Dra og Slipp', icon: MousePointer2, color: 'bg-amber-600' },
    { label: 'Minnespel', icon: Grid, color: 'bg-pink-600' },
    { label: 'Flere saman', icon: Layers, color: 'bg-purple-600' },
  ];

  return (
    <div className="space-y-20 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-24">

      {/* DEEP LINKING BANNER */}
      {isDeepLinking && (
          <div className="bg-blue-600 text-white p-8 rounded-3xl shadow-xl flex items-center justify-between animate-pulse" role="alert">
              <div className="flex items-center gap-6">
                  <div className="bg-white/20 p-4 rounded-2xl"><Plus size={32} aria-hidden="true"/></div>
                  <div>
                      <h2 className="text-3xl font-bold">Legg til i Canvas</h2>
                      <p className="text-blue-100 text-xl">Velg aktiviteten du vil sette inn, eller lag en ny.</p>
                  </div>
              </div>
          </div>
      )}

      {/* CREATE NEW */}
      <section className="pt-6" aria-labelledby="create-heading">
        <h2 id="create-heading" className="text-6xl font-extrabold text-slate-900 mb-12">Opprett ny</h2>
        <nav className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-8" aria-label="Velg aktivitetstype">
          {types.map((t) => (
            <button key={t.label} onClick={() => onCreate(t.label)} className="group relative flex flex-col items-center justify-center p-12 bg-white border border-slate-200 rounded-[2rem] hover:border-cyan-400 hover:shadow-2xl hover:-translate-y-2 transition-all duration-300" aria-label={`Opprett ny ${t.label}`}>
              <div className={`w-24 h-24 ${t.color} rounded-3xl flex items-center justify-center mb-8 shadow-lg relative group-hover:scale-110 transition-transform duration-300`}>
                <t.icon className="text-white w-12 h-12" aria-hidden="true" />
                <div className="absolute -bottom-3 -right-3 bg-white rounded-full p-2 shadow-sm border border-slate-100"><Plus className="w-6 h-6 text-slate-400" strokeWidth={4} aria-hidden="true" /></div>
              </div>
              <span className="font-bold text-slate-800 text-xl text-center leading-tight">{t.label}</span>
            </button>
          ))}
        </nav>
      </section>

      {/* LIBRARY */}
      <section aria-labelledby="library-heading">
        <h2 id="library-heading" className="text-6xl font-extrabold text-slate-900 mb-12">Bibliotek ({activities.length})</h2>
        {activities.length === 0 ? (
          <div className="text-center py-32 bg-slate-50 border-4 border-dashed border-slate-200 rounded-[3rem]">
            <div className="w-32 h-32 bg-slate-200 rounded-full flex items-center justify-center mx-auto mb-8 text-slate-500"><Layout size={64} aria-hidden="true"/></div>
            <p className="text-slate-700 font-bold text-3xl">Ingen aktivitetar oppretta ennå.</p>
            <p className="text-slate-500 text-xl mt-4 max-w-md mx-auto">Vel ein type ovanfor for å starte.</p>
          </div>
        ) : (
          <div className="grid gap-8 grid-cols-1 xl:grid-cols-2">
            {activities.map((a) => (
            <article key={a.id} className={`bg-white p-10 rounded-[2rem] border transition-all group gap-8 flex flex-col sm:flex-row items-start sm:items-center justify-between ${isDeepLinking ? 'border-blue-200 hover:border-blue-500 hover:shadow-xl hover:shadow-blue-100' : 'border-slate-200 hover:shadow-xl hover:border-cyan-200'}`}>
              <div className="flex items-center gap-8 overflow-hidden w-full">
                  <div className={`w-24 h-24 rounded-3xl flex items-center justify-center font-bold text-4xl shadow-inner flex-shrink-0 transition-colors ${isDeepLinking ? 'bg-blue-50 text-blue-600' : 'bg-gradient-to-br from-slate-100 to-slate-200 text-slate-600 group-hover:from-cyan-50 group-hover:to-cyan-100 group-hover:text-cyan-700'}`} aria-hidden="true">
                    {a.type.charAt(0)}
                  </div>
                  <div className="min-w-0 flex-1">
                    <h3 className="font-bold text-slate-900 truncate group-hover:text-cyan-900 text-3xl mb-2">{a.title}</h3>
                    <div className="flex flex-wrap items-center gap-4 text-lg text-slate-600">
                      <span className="bg-slate-100 px-4 py-1.5 rounded-lg text-slate-700 font-bold text-sm uppercase tracking-wide border border-slate-200">{a.type}</span>
                      <span>{new Date(a.createdAt).toLocaleDateString()}</span>
                    </div>
                    {a.description && <p className="text-lg text-slate-500 mt-4 truncate max-w-md opacity-80">{a.description}</p>}
                  </div>
              </div>
              <nav className="flex items-center gap-3 self-end sm:self-auto pl-4" aria-label={`Handlinger for ${a.title}`}>
                  {isDeepLinking && onSelect ? (
                      <button onClick={() => onSelect(a)} className="px-8 py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl transition-colors font-bold text-xl shadow-lg shadow-blue-200 flex items-center gap-2">
                          <Plus size={24} aria-hidden="true"/> Velg
                      </button>
                  ) : (
                      <>
                        <button onClick={() => onPlay(a)} className="p-5 text-slate-500 hover:text-cyan-600 hover:bg-cyan-50 rounded-2xl transition-colors" title="Spill" aria-label={`Spill ${a.title}`}>
                            <Play size={32} aria-hidden="true"/>
                        </button>
                        <button onClick={() => onEdit(a)} className="p-5 text-slate-500 hover:text-cyan-600 hover:bg-cyan-50 rounded-2xl transition-colors" title="Rediger" aria-label={`Rediger ${a.title}`}>
                            <Pencil size={32} aria-hidden="true"/>
                        </button>
                        <button onClick={() => setEmbedActivity(a)} className="p-5 text-indigo-600 hover:text-indigo-800 hover:bg-indigo-50 rounded-2xl transition-colors" title="Bygg inn i Canvas" aria-label={`Bygg inn ${a.title}`}>
                            <Code size={32} aria-hidden="true"/>
                        </button>
                        <button onClick={() => onDownloadHTML(a)} className="p-5 text-green-600 hover:text-green-800 hover:bg-green-50 rounded-2xl transition-colors" title="Last ned HTML" aria-label={`Last ned ${a.title}`}>
                            <Share2 size={32} aria-hidden="true"/>
                        </button>
                        <div className="w-px h-12 bg-slate-200 mx-2" aria-hidden="true"></div>
                        <button onClick={() => onDuplicate(a)} className="p-5 text-slate-400 hover:text-cyan-600 hover:bg-cyan-50 rounded-2xl transition-colors" title="Dupliser" aria-label={`Dupliser ${a.title}`}>
                            <Copy size={28} aria-hidden="true"/>
                        </button>
                        <DeleteButton onDelete={() => onDelete(a.id)} />
                      </>
                  )}
              </nav>
            </article>
          ))}</div>
        )}
      </section>

      {/* EMBED MODAL */}
      {embedActivity && (
          <EmbedDialog 
              activity={embedActivity} 
              onClose={() => setEmbedActivity(null)} 
              onDownload={onDownloadHTML} 
          />
      )}
    </div>
  );
}
